package kotlinx.coroutines.future

import kotlinx.coroutines.*
import org.junit.Test
import kotlin.test.assertTrue

class FutureCancellationDoesNotReportToGlobalHandlerTest : TestBase() {

    @Test
    fun testCancellationDoesNotReportUnhandledException() = runBlocking {
        val started = CompletableDeferred<Unit>()
        val proceed = CompletableDeferred<Unit>()
        val finished = CompletableDeferred<Unit>()

        val future = GlobalScope.future(Dispatchers.Default) {
            try {
                started.complete(Unit)
                withContext(NonCancellable) { proceed.await() }
                error("foo")
            } finally {
                finished.complete(Unit)
            }
        }

        started.await()
        future.cancel(true)
        proceed.complete(Unit)

        withTimeout(5_000) { finished.await() }
        assertTrue(future.isCancelled)
    }
}
